def calculate_quarter_scores():
    scores = {
        '1st_quarter': {
            'Pittsburgh': 7,
            'OregonState': 7
        },
        '2nd_quarter': {
            'Pittsburgh': 10,
            'OregonState': 10
        },
        '3rd_quarter': {
            'Pittsburgh': 24,
            'OregonState': 13
        },
        '4th_quarter': {
            'Pittsburgh': 38,
            'OregonState': 13
        }
    }
    return scores

quarter_scores = calculate_quarter_scores()
for quarter, score in quarter_scores.items():
    difference = score['Pittsburgh'] - score['OregonState']
    print(f"{quarter}: Pittsburgh leads by {difference} points")

This function returns the cumulative scores for each team at the end of every quarter and calculates the point difference.
